// @ts-nocheck
const METADATA = {
    website: "https://github.com/ct-yx/shapez-mods",
    author: "ct-yx & Codex",
    name: "Balancer Variants",
    version: "1.0.1",
    id: "balancer-variants-ctyx",
    description: "Adds 4-way, 5-way, 8-way, 10-way and 16-way balancers to the vanilla balancer variants.",
    minimumGameVersion: ">=1.5.0",
};

const VARIANTS = [4, 5, 8, 10, 16].map(ways => ({
    ways,
    id: "balancer_" + ways + "way",
    variant: "balancer_" + ways + "way",
    name: ways + "-way balancer",
    nameZh: ways + "-way 平衡器",
}));

function registerProcessorType(config) {
    const processorType = config.id;
    shapez.enumItemProcessorTypes[processorType] = processorType;
    shapez.MOD_ITEM_PROCESSOR_SPEEDS[processorType] = () => 1000;
    shapez.MOD_ITEM_PROCESSOR_HANDLERS[processorType] = function(payload) {
        const components = payload && payload.entity && payload.entity.components;
        const ejector = components && components.ItemEjector;
        const processor = components && components.ItemProcessor;
        const items = payload && payload.items;
        const outItems = payload && payload.outItems;
        const availableSlots = ejector && Array.isArray(ejector.slots)
            ? ejector.slots.length
            : 0;

        // A variant can briefly be rebuilt while the placement preview is
        // changing. Do not let an incomplete preview produce a modulo-by-zero
        // slot or throw from the processor system.
        if (!processor || !items || !outItems || availableSlots === 0) return false;

        for (let index = 0; index < config.ways; ++index) {
            const item = typeof items.get === "function" ? items.get(index) : null;
            if (!item) continue;
            outItems.push({
                item,
                preferredSlot: processor.nextOutputSlot++ % availableSlots,
                doNotTrack: true,
            });
        }
        return true;
    };
}

function makeSlots(count, direction) {
    const slots = [];
    for (let index = 0; index < count; ++index) {
        slots.push({
            pos: new shapez.Vector(index, 0),
            direction,
        });
    }
    return slots;
}

function updateWideBalancer(entity, config) {
    const components = entity && entity.components;
    if (!components) return false;

    const acceptor = components.ItemAcceptor;
    const processor = components.ItemProcessor;
    const ejector = components.ItemEjector;
    const underlays = components.BeltUnderlays;
    if (!acceptor || !processor || !ejector || !underlays) return false;

    // The preview entity may be switched several times in a single frame.
    // Clear transient processing state before changing the slot topology so
    // queued outputs from the previous width cannot target stale slots.
    if (typeof processor.clear === "function") processor.clear();

    acceptor.setSlots(
        makeSlots(config.ways, shapez.enumDirection.bottom)
    );
    processor.type = shapez.enumItemProcessorTypes[config.id];
    processor.inputsPerCharge = 1;
    processor.processingRequirement = null;
    ejector.setSlots(
        makeSlots(config.ways, shapez.enumDirection.top)
    );
    underlays.underlays = makeSlots(
        config.ways,
        shapez.enumDirection.top
    );
    return true;
}

class Mod extends shapez.Mod {
    init() {
        for (const config of VARIANTS) registerProcessorType(config);

        const metaBalancer = shapez.MetaBalancerBuilding;
        if (!metaBalancer || !this.modInterface.addVariantToExistingBuilding) {
            throw new Error("Balancer Variants requires the vanilla balancer API");
        }

        for (const config of VARIANTS) {
            this.modInterface.addVariantToExistingBuilding(metaBalancer, config.variant, {
                rotationVariants: [0],
                dimensions: new shapez.Vector(config.ways, 1),
                regularSpriteBase64: RESOURCES["balancer-" + config.ways + ".png"],
                blueprintSpriteBase64: RESOURCES["balancer-" + config.ways + "-blueprint.png"],
                name: config.name,
                description: "A " + config.ways + "-lane balancer variant.",
                isUnlocked: () => true,
            });
            this.modInterface.registerBuildingTranslation(metaBalancer, config.variant, {
                language: "zh-CN",
                name: config.nameZh,
                description: config.ways + " 路输入/输出的平衡器变形体。",
            });
        }

        // addVariantToExistingBuilding registers the variant list and sprite,
        // while the vanilla class still needs its component layout changed for
        // each custom width. No toolbar entry is added: T cycles these variants
        // exactly where the vanilla balancer's variants are shown.
        this.modInterface.extendClass(metaBalancer, ({ $old }) => ({
            updateVariants(entity, rotationVariant, variant) {
                const config = VARIANTS.find(item => item.variant === variant);
                if (config) {
                    updateWideBalancer(entity, config);
                    return;
                }
                return $old.updateVariants.call(this, entity, rotationVariant, variant);
            },
        }));
    }
}

const RESOURCES = {
    "balancer-4.png": "data:image/png;base64,",
    "balancer-4-blueprint.png": "data:image/png;base64,",
    "balancer-5.png": "data:image/png;base64,",
    "balancer-5-blueprint.png": "data:image/png;base64,",
    "balancer-8.png": "data:image/png;base64,",
    "balancer-8-blueprint.png": "data:image/png;base64,",
    "balancer-10.png": "data:image/png;base64,",
    "balancer-10-blueprint.png": "data:image/png;base64,",
    "balancer-16.png": "data:image/png;base64,",
    "balancer-16-blueprint.png": "data:image/png;base64,",
};
